import { AutkSpatialDb } from '@urban-toolkit/autk-db';

// Load Niterói's OSM surface, parks, water, and roads from Overpass.
// Layers are emitted in EPSG:4326 (WGS84) so the downstream JS_COMPUTATION
// can re-ingest them via loadCustomLayer — which always assumes the input
// FeatureCollection is in EPSG:4326 — and reproject to a metric CRS for the
// spatial join.
const db = new AutkSpatialDb();
await db.init();

await db.loadOsm({
    queryArea: { geocodeArea: 'Rio de Janeiro', areas: ['Niterói'] },
    outputTableName: 'table_osm',
    autoLoadLayers: {
        coordinateFormat: 'EPSG:4326',
        layers: ['surface', 'parks', 'water', 'roads'],
        dropOsmTable: true,
    },
});

const layers = [];
for (const layer of db.getLayerTables()) {
    layers.push({ name: layer.name, type: layer.type, geojson: await db.getLayer(layer.name) });
}
return layers;

import { AutkSpatialDb } from '@urban-toolkit/autk-db';

// arg[0] = OSM layer array (EPSG:4326) from niteroi-osm
// arg[1] = single-row FeatureCollection carrying the GeoTIFF bytes (base64)
const [osmLayers, rasterFc] = arg;
if (!Array.isArray(osmLayers)) throw new Error('osm layers missing from upstream');
const geotiffB64 = rasterFc?.features?.[0]?.properties?.geotiff_b64;
if (!geotiffB64) throw new Error('geotiff_b64 missing from upstream raster row');

// Decode the base64-embedded raster bytes back into a clean ArrayBuffer
// (slicing off any Buffer prefix so loadGeoTiff sees just the raster).
const nodeBuf = Buffer.from(geotiffB64, 'base64');
const geotiffArrayBuffer = nodeBuf.buffer.slice(
    nodeBuf.byteOffset,
    nodeBuf.byteOffset + nodeBuf.byteLength,
);

const BAND_COUNT = 24;

const db = new AutkSpatialDb();
await db.init();

// Re-ingest each OSM layer (already in EPSG:4326) as a custom table and
// project to EPSG:3395 so the metric NEAR distance works.
for (const layer of osmLayers) {
    await db.loadCustomLayer({
        geojsonObject: layer.geojson,
        outputTableName: layer.name,
        coordinateFormat: 'EPSG:3395',
        layerType: layer.type,
    });
}

// Reuse the bytes the Python DataLoading node already fetched — no second
// HTTP request, no URL needed here.
await db.loadGeoTiff({
    geotiffArrayBuffer,
    outputTableName: 'lst',
    sourceCrs: 'EPSG:4326',
    coordinateFormat: 'EPSG:3395',
});

// Spatial join: average each LST band within 1 km of every road segment.
await db.spatialQuery({
    tableRootName: 'table_osm_roads',
    tableJoinName: 'lst',
    spatialPredicate: 'NEAR',
    nearDistance: 1000,
    output: { type: 'MODIFY_ROOT' },
    joinType: 'LEFT',
    groupBy: {
        selectColumns: Array.from({ length: BAND_COUNT }, (_, i) => ({
            tableName: 'lst',
            column: `band_${i + 1}`,
            aggregateFn: 'avg',
            aggregateFnResultColumnName: `band_${i + 1}`,
        })),
    },
});

// Reshape per-band averages into a single lst_timeseries array per road.
const bandSelects = Array.from({ length: BAND_COUNT }, (_, i) =>
    `COALESCE(json_extract(properties, '$.sjoin.avg.band_${i + 1}')::DOUBLE, 0)`
).join(', ');

await db.rawQuery({
    query: `
        SELECT
            geometry,
            json_merge_patch(
                COALESCE(CAST(properties AS JSON), '{}'::JSON),
                json_object('lst_timeseries', [${bandSelects}])
            ) AS properties
        FROM table_osm_roads
    `,
    output: { type: 'CREATE_TABLE', tableName: 'table_osm_roads', source: 'osm', tableType: 'roads' },
});

// Rebuild the layer array uniformly from the local db (all in EPSG:3395)
// so the downstream map gets a consistent CRS across surface/parks/water/roads.
const layers = [];
for (const layer of osmLayers) {
    layers.push({
        name: layer.name,
        type: layer.type,
        geojson: await db.getLayer(layer.name),
    });
}
layers.push({ name: 'lst', type: 'raster', geojson: await db.getGeoTiffLayer('lst') });

return layers;

// Per-road OLS regression of yearly LST values via GPU shader.
const roads = arg.find(l => l.name === 'table_osm_roads')?.geojson;
if (!roads) throw new Error('roads layer missing from upstream');

const BAND_COUNT = 24;
const START_YEAR = 2001;

// Mirrors the upstream Autark reference shader at
// usecases/src/niteroi/lst-regression-shader.ts — out[0] is the warming
// angle (atan of slope, in degrees), out[1] the regression intercept.
const wgslBody = `
  var n = f32(bands_length);
  var sum_x  = 0.0;
  var sum_y  = 0.0;
  var sum_xy = 0.0;
  var sum_x2 = 0.0;

  for (var i = 0u; i < bands_length; i++) {
    let x   = f32(i);
    let y   = bands[i];
    sum_x  += x;
    sum_y  += y;
    sum_xy += x * y;
    sum_x2 += x * x;
  }

  let denom = n * sum_x2 - sum_x * sum_x;
  var slope     = 0.0;
  var intercept = 0.0;
  if (denom != 0.0) {
    slope     = (n * sum_xy - sum_x * sum_y) / denom;
    intercept = (sum_y - slope * sum_x) / n;
  }

  var out: OutputArray;
  out[0] = atan(slope) * (180.0 / 3.14159265358979);
  out[1] = intercept;
  return out;
`;

const compute = new ComputeGpgpu();
let computedRoads = await compute.run({
    collection: roads,
    variableMapping: { bands: 'lst_timeseries' },
    attributeArrays: { bands: BAND_COUNT },
    outputColumns: ['angle', 'intercept'],
    wgslBody,
});

// Convert per-feature band arrays into {timestamp, value} so any downstream
// timeseries chart can use year strings as bucket keys.
computedRoads = {
    ...computedRoads,
    features: computedRoads.features.map(f => ({
        ...f,
        properties: {
            ...f.properties,
            lst_timeseries: ((f.properties?.lst_timeseries ?? [])).map((v, i) => ({
                timestamp: String(START_YEAR + i),
                value: v,
            })),
        },
    })),
};

return arg.map(l => l.name === 'table_osm_roads'
    ? { ...l, geojson: computedRoads }
    : l);

// Render the OSM layer stack with the LST raster underneath, and
// color roads by their warming angle.
const map = new AutkMap(container);
await map.init();
for (const layer of arg) {
    map.loadCollection(layer.name, { collection: layer.geojson, type: layer.type });
}
map.updateRenderInfo('lst', { isSkip: true, opacity: 0.65 });
map.updateRenderInfo('table_osm_roads', { isPick: true, isColorMap: true });
map.updateThematic('table_osm_roads', {
    collection: arg.find(l => l.name === 'table_osm_roads').geojson,
    property: 'properties.compute.angle',
});
map.draw();
return map;

// Scatterplot: baseline LST vs warming angle, brushable.
const roads = arg.find(l => l.name === 'table_osm_roads')?.geojson ?? arg[0]?.geojson;
return new AutkPlot(container, {
    type: 'scatterplot',
    collection: roads,
    attributes: { axis: ['compute.intercept', 'compute.angle'] },
    labels: { axis: ['Baseline LST (°C)', 'Warming angle (°)'], title: 'LST regression' },
    tickFormats: ['.1~f', '.3~f'],
    width: 600,
    height: 380,
    events: ['brush'],
});
